proof fn phi_1_leads_to_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>, i: nat)
    requires
        p.leads_to(q).satisfied_by(ex),
    ensures
        p.implies(eventually(q)).satisfied_by(ex.suffix(i)),
{
    leads_to_unfold::<int>(ex, p, q);
}

proof fn phi_2_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_3_always_propagate_forwards_intensional_bridge(ex: Execution<int>, p: TempPred<int>, i: nat, j: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        always(p).satisfied_by(ex.suffix(i)),
{
    always_propagate_forwards::<int>(ex, p, i);
}

proof fn phi_4_pack_conditions_weakens_spec(spec: TempPred<int>, c: TempPred<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        spec.entails(p.and(c).leads_to(q)),
    ensures
        spec.and(always(c)).entails(p.leads_to(q)),
{
    pack_conditions_to_spec::<int>(spec, c, p, q);
}

proof fn phi_5_false_spec_any_leads_to(p: TempPred<int>, q: TempPred<int>)
    requires
        TempPred::<int>::new(|ex: Execution<int>| false).entails(p.and(TempPred::new(|ex: Execution<int>| false)).leads_to(q)),
    ensures
        TempPred::<int>::new(|ex: Execution<int>| false).and(always(TempPred::new(|ex: Execution<int>| false))).entails(p.leads_to(q)),
{
    pack_conditions_to_spec::<int>(TempPred::new(|ex: Execution<int>| false), TempPred::new(|ex: Execution<int>| false), p, q);
}
